-- calc_cities_name
-- Field: Cities.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_cities_name(p_city_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(display_name, '') FROM cities WHERE city_id = p_city_id))::text;
$$ LANGUAGE sql STABLE;

