-- calc_tsp_instances_expected_undirected_edge_count
-- Field: TSPInstances.ExpectedUndirectedEdgeCount
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_tsp_instances_expected_undirected_edge_count(p_tsp_instance_id TEXT)
RETURNS INTEGER AS $$
