-- calc_tsp_graph_invariant_checks_name
-- Field: TSPGraphInvariantChecks.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_tsp_graph_invariant_checks_name(p_tsp_graph_invariant_check_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(display_name, '') FROM tsp_graph_invariant_checks WHERE tsp_graph_invariant_check_id = p_tsp_graph_invariant_check_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_tsp_graph_invariant_checks_is_passing
-- Field: TSPGraphInvariantChecks.IsPassing
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_graph_invariant_checks_is_passing(p_tsp_graph_invariant_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT expected_complete_undirected_graph FROM tsp_graph_invariant_checks WHERE tsp_graph_invariant_check_id = p_tsp_graph_invariant_check_id) = calc_tsp_graph_invariant_checks_actual_complete_undirected_grap(p_tsp_graph_invariant_check_id) AND (SELECT expected_travel_edge_count FROM tsp_graph_invariant_checks WHERE tsp_graph_invariant_check_id = p_tsp_graph_invariant_check_id) = calc_tsp_graph_invariant_checks_actual_travel_edge_count(p_tsp_graph_invariant_check_id) AND (SELECT expected_non_unique_edge_pair_rows FROM tsp_graph_invariant_checks WHERE tsp_graph_invariant_check_id = p_tsp_graph_invariant_check_id) = calc_tsp_graph_invariant_checks_actual_non_unique_edge_pair_row(p_tsp_graph_invariant_check_id)))::boolean;
$$ LANGUAGE sql STABLE;

