-- calc_instance_stops_count_of_canonical_edges_from
-- Field: InstanceStops.CountOfCanonicalEdgesFrom
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_stops_count_of_canonical_edges_from(p_instance_stop_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM travel_edges WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id) AND from_stop = (SELECT NULLIF(instance_stop_id, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_stops_count_of_canonical_edges_to
-- Field: InstanceStops.CountOfCanonicalEdgesTo
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_stops_count_of_canonical_edges_to(p_instance_stop_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM travel_edges WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id) AND to_stop = (SELECT NULLIF(instance_stop_id, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_stops_count_of_incident_edges
-- Field: InstanceStops.CountOfIncidentEdges
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_stops_count_of_incident_edges(p_instance_stop_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_instance_stops_count_of_canonical_edges_from(p_instance_stop_id)) AS v) __safe_numeric), 0) + COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_instance_stops_count_of_canonical_edges_to(p_instance_stop_id)) AS v) __safe_numeric), 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_stops_count_of_admissible_edges_from
-- Field: InstanceStops.CountOfAdmissibleEdgesFrom
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_stops_count_of_admissible_edges_from(p_instance_stop_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM travel_edges WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id) AND from_stop = (SELECT NULLIF(instance_stop_id, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id) AND calc_travel_edges_is_admissible(travel_edge_id) = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_stops_count_of_admissible_edges_to
-- Field: InstanceStops.CountOfAdmissibleEdgesTo
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_stops_count_of_admissible_edges_to(p_instance_stop_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM travel_edges WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id) AND to_stop = (SELECT NULLIF(instance_stop_id, '') FROM instance_stops WHERE instance_stop_id = p_instance_stop_id) AND calc_travel_edges_is_admissible(travel_edge_id) = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_stops_count_of_admissible_incident_edges
-- Field: InstanceStops.CountOfAdmissibleIncidentEdges
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_stops_count_of_admissible_incident_edges(p_instance_stop_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_instance_stops_count_of_admissible_edges_from(p_instance_stop_id)) AS v) __safe_numeric), 0) + COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_instance_stops_count_of_admissible_edges_to(p_instance_stop_id)) AS v) __safe_numeric), 0)))::integer;
$$ LANGUAGE sql STABLE;

