-- calc_travel_edges_name
-- Field: TravelEdges.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_travel_edges_name(p_travel_edge_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(travel_edge_id, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_expected_canonical_pair_key
-- Field: TravelEdges.ExpectedCanonicalPairKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_travel_edges_expected_canonical_pair_key(p_travel_edge_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN (SELECT NULLIF(from_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) < (SELECT NULLIF(to_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) THEN (CONCAT((SELECT NULLIF(from_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id), '|', (SELECT NULLIF(to_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id)))::text ELSE (CONCAT((SELECT NULLIF(to_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id), '|', (SELECT NULLIF(from_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id)))::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_is_canonical_pair_key_correct
-- Field: TravelEdges.IsCanonicalPairKeyCorrect
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_travel_edges_is_canonical_pair_key_correct(p_travel_edge_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(canonical_pair_key, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) = calc_travel_edges_expected_canonical_pair_key(p_travel_edge_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_is_canonical_endpoint_order
-- Field: TravelEdges.IsCanonicalEndpointOrder
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_travel_edges_is_canonical_endpoint_order(p_travel_edge_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(from_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) < (SELECT NULLIF(to_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_pair_multiplicity
-- Field: TravelEdges.PairMultiplicity
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_travel_edges_pair_multiplicity(p_travel_edge_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM travel_edges WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) AND canonical_pair_key = (SELECT NULLIF(canonical_pair_key, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_is_unique_canonical_pair
-- Field: TravelEdges.IsUniqueCanonicalPair
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_travel_edges_is_unique_canonical_pair(p_travel_edge_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_travel_edges_pair_multiplicity(p_travel_edge_id))::NUMERIC = 1)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_is_self_loop
-- Field: TravelEdges.IsSelfLoop
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_travel_edges_is_self_loop(p_travel_edge_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT NULLIF(from_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) = (SELECT NULLIF(to_stop, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_is_within_instance
-- Field: TravelEdges.IsWithinInstance
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_travel_edges_is_within_instance(p_travel_edge_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(tsp_instance, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) = calc_travel_edges_from_tsp_instance(p_travel_edge_id) AND (SELECT NULLIF(tsp_instance, '') FROM travel_edges WHERE travel_edge_id = p_travel_edge_id) = calc_travel_edges_to_tsp_instance(p_travel_edge_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_travel_edges_is_admissible
-- Field: TravelEdges.IsAdmissible
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_travel_edges_is_admissible(p_travel_edge_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((COALESCE((SELECT is_available FROM travel_edges WHERE travel_edge_id = p_travel_edge_id), FALSE) AND NOT (calc_travel_edges_is_self_loop(p_travel_edge_id)) AND calc_travel_edges_is_within_instance(p_travel_edge_id) AND calc_travel_edges_is_canonical_endpoint_order(p_travel_edge_id) AND calc_travel_edges_is_canonical_pair_key_correct(p_travel_edge_id) AND calc_travel_edges_is_unique_canonical_pair(p_travel_edge_id)))::boolean;
$$ LANGUAGE sql STABLE;

