-- calc_candidate_tours_is_hamiltonian_cycle_witness
-- Field: CandidateTours.IsHamiltonianCycleWitness
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_candidate_tours_is_hamiltonian_cycle_witness(p_candidate_tour_id TEXT)
RETURNS BOOLEAN AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_candidate_tours_required_stop_count(p_candidate_tour_id) AS val) SELECT ((calc_candidate_tours_count_of_tour_stops(p_candidate_tour_id) = (SELECT val FROM __erb_dedup_v1) AND calc_candidate_tours_count_of_tour_legs(p_candidate_tour_id) = (SELECT val FROM __erb_dedup_v1) AND (calc_candidate_tours_count_of_non_unique_visits(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_non_unique_sequences(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_out_of_instance_stops(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_non_required_stops(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_depot_stops(p_candidate_tour_id))::NUMERIC = 1 AND (calc_candidate_tours_count_of_depot_position_violations(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_invalid_legs(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_cycle_degree_violations(p_candidate_tour_id))::NUMERIC = 0 AND (calc_candidate_tours_count_of_non_unique_leg_orders(p_candidate_tour_id))::NUMERIC = 0));
$$ LANGUAGE sql STABLE;

-- calc_candidate_tours_count_of_passing_optimality_certificates
-- Field: CandidateTours.CountOfPassingOptimalityCertificates
