RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM optimality_certificates WHERE candidate_tour = (SELECT NULLIF(candidate_tour_id, '') FROM candidate_tours WHERE candidate_tour_id = p_candidate_tour_id) AND calc_optimality_certificates_is_passing(optimality_certificate_id) = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_candidate_tours_is_optimality_proved
-- Field: CandidateTours.IsOptimalityProved
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_candidate_tours_is_optimality_proved(p_candidate_tour_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_candidate_tours_is_hamiltonian_cycle_witness(p_candidate_tour_id) AND (calc_candidate_tours_count_of_passing_optimality_certificates(p_candidate_tour_id))::NUMERIC > 0));
$$ LANGUAGE sql STABLE;

-- calc_candidate_tours_residual_claim
-- Field: CandidateTours.ResidualClaim
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_candidate_tours_residual_claim(p_candidate_tour_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_candidate_tours_is_optimality_proved(p_candidate_tour_id) THEN ('OPTIMAL_FOR_DECLARED_FINITE_INSTANCE')::text ELSE (CASE WHEN calc_candidate_tours_is_hamiltonian_cycle_witness(p_candidate_tour_id) THEN ('VALID_TOUR_NOT_OPTIMALITY_PROOF')::text ELSE ('INVALID_TOUR')::text END)::text END)::text;
$$ LANGUAGE sql STABLE;

