  SELECT ((SELECT COUNT(*) FROM tour_legs WHERE candidate_tour = (SELECT NULLIF(candidate_tour, '') FROM tour_stops WHERE tour_stop_id = p_tour_stop_id) AND to_tour_stop = (SELECT NULLIF(tour_stop_id, '') FROM tour_stops WHERE tour_stop_id = p_tour_stop_id)))::integer;
$$ LANGUAGE sql STABLE;

