  SELECT ((SELECT COUNT(*) FROM tour_legs WHERE candidate_tour = (SELECT NULLIF(candidate_tour, '') FROM tour_legs WHERE tour_leg_id = p_tour_leg_id) AND leg_order = (SELECT leg_order FROM tour_legs WHERE tour_leg_id = p_tour_leg_id)))::integer;
