$$ LANGUAGE sql STABLE;

-- calc_tour_legs_is_candidate_membership_valid
-- Field: TourLegs.IsCandidateMembershipValid
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tour_legs_is_candidate_membership_valid(p_tour_leg_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(candidate_tour, '') FROM tour_legs WHERE tour_leg_id = p_tour_leg_id) = calc_tour_legs_from_tour_candidate(p_tour_leg_id) AND (SELECT NULLIF(candidate_tour, '') FROM tour_legs WHERE tour_leg_id = p_tour_leg_id) = calc_tour_legs_to_tour_candidate(p_tour_leg_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tour_legs_is_sequence_transition
-- Field: TourLegs.IsSequenceTransition
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tour_legs_is_sequence_transition(p_tour_leg_id TEXT)
RETURNS BOOLEAN AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_tour_legs_to_sequence_position(p_tour_leg_id) AS val), __erb_dedup_v2 AS (SELECT calc_tour_legs_from_sequence_position(p_tour_leg_id) AS val) SELECT (((SELECT val FROM __erb_dedup_v1) = (COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT val FROM __erb_dedup_v2)) AS v) __safe_numeric), 0) + COALESCE(1, 0)) OR ((SELECT val FROM __erb_dedup_v2) = calc_tour_legs_required_stop_count(p_tour_leg_id) AND ((SELECT val FROM __erb_dedup_v1))::NUMERIC = 1)));
$$ LANGUAGE sql STABLE;

-- calc_tour_legs_is_edge_endpoint_match
-- Field: TourLegs.IsEdgeEndpointMatch
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tour_legs_is_edge_endpoint_match(p_tour_leg_id TEXT)
RETURNS BOOLEAN AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_tour_legs_from_instance_stop(p_tour_leg_id) AS val), __erb_dedup_v2 AS (SELECT calc_tour_legs_edge_from_stop(p_tour_leg_id) AS val), __erb_dedup_v3 AS (SELECT calc_tour_legs_to_instance_stop(p_tour_leg_id) AS val), __erb_dedup_v4 AS (SELECT calc_tour_legs_edge_to_stop(p_tour_leg_id) AS val) SELECT ((((SELECT val FROM __erb_dedup_v1) = (SELECT val FROM __erb_dedup_v2) AND (SELECT val FROM __erb_dedup_v3) = (SELECT val FROM __erb_dedup_v4)) OR ((SELECT val FROM __erb_dedup_v1) = (SELECT val FROM __erb_dedup_v4) AND (SELECT val FROM __erb_dedup_v3) = (SELECT val FROM __erb_dedup_v2))))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tour_legs_is_in_tour_instance
-- Field: TourLegs.IsInTourInstance
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tour_legs_is_in_tour_instance(p_tour_leg_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_tour_legs_edge_tsp_instance(p_tour_leg_id) = calc_tour_legs_tour_tsp_instance(p_tour_leg_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tour_legs_is_valid
-- Field: TourLegs.IsValid
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tour_legs_is_valid(p_tour_leg_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_tour_legs_is_candidate_membership_valid(p_tour_leg_id) AND calc_tour_legs_is_sequence_transition(p_tour_leg_id) AND calc_tour_legs_is_edge_endpoint_match(p_tour_leg_id) AND calc_tour_legs_is_in_tour_instance(p_tour_leg_id) AND calc_tour_legs_edge_is_admissible(p_tour_leg_id) AND calc_tour_legs_is_unique_leg_order(p_tour_leg_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tour_legs_travel_cost
-- Field: TourLegs.TravelCost
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_tour_legs_travel_cost(p_tour_leg_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN calc_tour_legs_is_valid(p_tour_leg_id) THEN (calc_tour_legs_edge_travel_cost(p_tour_leg_id))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

