  SELECT (((SELECT NULLIF(instance_stop, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id) = calc_local_degree_bounds_first_edge_from_stop(p_local_degree_bound_id) OR (SELECT NULLIF(instance_stop, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id) = calc_local_degree_bounds_first_edge_to_stop(p_local_degree_bound_id)))::boolean;
