$$ LANGUAGE sql STABLE;

-- calc_local_degree_bounds_are_selected_edges_distinct
-- Field: LocalDegreeBounds.AreSelectedEdgesDistinct
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


