  SELECT ((SELECT NULLIF(first_edge, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id) <> (SELECT NULLIF(second_edge, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id))::boolean;
