-- calc_local_degree_bounds_required_dominance_check_count
-- Field: LocalDegreeBounds.RequiredDominanceCheckCount
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_local_degree_bounds_required_dominance_check_count(p_local_degree_bound_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_local_degree_bounds_stop_admissible_incident_edge_count(p_local_degree_bound_id)) AS v) __safe_numeric), 0) - COALESCE(2, 0)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_local_degree_bounds_count_of_dominance_checks
-- Field: LocalDegreeBounds.CountOfDominanceChecks
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_local_degree_bounds_count_of_dominance_checks(p_local_degree_bound_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM incident_dominance_checks WHERE local_degree_bound = (SELECT NULLIF(local_degree_bound_id, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_local_degree_bounds_count_of_failed_dominance_checks
-- Field: LocalDegreeBounds.CountOfFailedDominanceChecks
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_local_degree_bounds_count_of_failed_dominance_checks(p_local_degree_bound_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM incident_dominance_checks WHERE local_degree_bound = (SELECT NULLIF(local_degree_bound_id, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id) AND calc_incident_dominance_checks_is_passing(incident_dominance_check_id) = FALSE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_local_degree_bounds_is_two_cheapest_witness
-- Field: LocalDegreeBounds.IsTwoCheapestWitness
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_local_degree_bounds_is_two_cheapest_witness(p_local_degree_bound_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(tsp_instance, '') FROM local_degree_bounds WHERE local_degree_bound_id = p_local_degree_bound_id) = calc_local_degree_bounds_stop_tsp_instance(p_local_degree_bound_id) AND calc_local_degree_bounds_is_first_edge_incident(p_local_degree_bound_id) AND calc_local_degree_bounds_is_second_edge_incident(p_local_degree_bound_id) AND calc_local_degree_bounds_are_selected_edges_distinct(p_local_degree_bound_id) AND calc_local_degree_bounds_are_selected_costs_ordered(p_local_degree_bound_id) AND calc_local_degree_bounds_count_of_dominance_checks(p_local_degree_bound_id) = calc_local_degree_bounds_required_dominance_check_count(p_local_degree_bound_id) AND (calc_local_degree_bounds_count_of_failed_dominance_checks(p_local_degree_bound_id))::NUMERIC = 0));
$$ LANGUAGE sql STABLE;

-- calc_local_degree_bounds_local_bound_cost
-- Field: LocalDegreeBounds.LocalBoundCost
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_local_degree_bounds_local_bound_cost(p_local_degree_bound_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN calc_local_degree_bounds_is_two_cheapest_witness(p_local_degree_bound_id) THEN ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_local_degree_bounds_first_edge_cost(p_local_degree_bound_id)) AS v) __safe_numeric), 0) + COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_local_degree_bounds_second_edge_cost(p_local_degree_bound_id)) AS v) __safe_numeric), 0)))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_bound_stop
-- Field: IncidentDominanceChecks.BoundStop
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: InstanceStop from related LocalDegreeBounds


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_bound_stop(p_incident_dominance_check_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT instance_stop::text FROM local_degree_bounds WHERE local_degree_bound_id = (SELECT local_degree_bound FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id));
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_first_selected_edge
-- Field: IncidentDominanceChecks.FirstSelectedEdge
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: FirstEdge from related LocalDegreeBounds


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_first_selected_edge(p_incident_dominance_check_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT first_edge::text FROM local_degree_bounds WHERE local_degree_bound_id = (SELECT local_degree_bound FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id));
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_second_selected_edge
-- Field: IncidentDominanceChecks.SecondSelectedEdge
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: SecondEdge from related LocalDegreeBounds


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_second_selected_edge(p_incident_dominance_check_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT second_edge::text FROM local_degree_bounds WHERE local_degree_bound_id = (SELECT local_degree_bound FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id));
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_second_selected_edge_cost
-- Field: IncidentDominanceChecks.SecondSelectedEdgeCost
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: SecondEdgeCost from related LocalDegreeBounds


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_second_selected_edge_cost(p_incident_dominance_check_id TEXT)
RETURNS NUMERIC AS $$
  SELECT calc_local_degree_bounds_second_edge_cost((SELECT local_degree_bound FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id));
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_other_edge_from_stop
-- Field: IncidentDominanceChecks.OtherEdgeFromStop
-- Type: lookup | DataType: string | Returns: TEXT
