RETURNS TEXT AS $$
  SELECT (SELECT from_stop::text FROM travel_edges WHERE travel_edge_id = (SELECT other_edge FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id));
