CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_name(p_incident_dominance_check_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(incident_dominance_check_id, '') FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_other_edge_multiplicity
-- Field: IncidentDominanceChecks.OtherEdgeMultiplicity
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_other_edge_multiplicity(p_incident_dominance_check_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM incident_dominance_checks WHERE local_degree_bound = (SELECT NULLIF(local_degree_bound, '') FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id) AND other_edge = (SELECT NULLIF(other_edge, '') FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_is_other_edge_incident
-- Field: IncidentDominanceChecks.IsOtherEdgeIncident
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_is_other_edge_incident(p_incident_dominance_check_id TEXT)
RETURNS BOOLEAN AS $$
  WITH __erb_dedup_v1 AS (SELECT calc_incident_dominance_checks_bound_stop(p_incident_dominance_check_id) AS val) SELECT (((SELECT val FROM __erb_dedup_v1) = calc_incident_dominance_checks_other_edge_from_stop(p_incident_dominance_check_id) OR (SELECT val FROM __erb_dedup_v1) = calc_incident_dominance_checks_other_edge_to_stop(p_incident_dominance_check_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_is_other_edge_unselected
-- Field: IncidentDominanceChecks.IsOtherEdgeUnselected
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_is_other_edge_unselected(p_incident_dominance_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT NULLIF(other_edge, '') FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id) <> calc_incident_dominance_checks_first_selected_edge(p_incident_dominance_check_id) AND (SELECT NULLIF(other_edge, '') FROM incident_dominance_checks WHERE incident_dominance_check_id = p_incident_dominance_check_id) <> calc_incident_dominance_checks_second_selected_edge(p_incident_dominance_check_id)))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_is_other_edge_unique
-- Field: IncidentDominanceChecks.IsOtherEdgeUnique
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_is_other_edge_unique(p_incident_dominance_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_incident_dominance_checks_other_edge_multiplicity(p_incident_dominance_check_id))::NUMERIC = 1)::boolean;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_is_dominated_by_second_cost
-- Field: IncidentDominanceChecks.IsDominatedBySecondCost
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_is_dominated_by_second_cost(p_incident_dominance_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_incident_dominance_checks_other_edge_cost(p_incident_dominance_check_id) >= calc_incident_dominance_checks_second_selected_edge_cost(p_incident_dominance_check_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_incident_dominance_checks_is_passing
-- Field: IncidentDominanceChecks.IsPassing
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_incident_dominance_checks_is_passing(p_incident_dominance_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_incident_dominance_checks_is_other_edge_incident(p_incident_dominance_check_id) AND calc_incident_dominance_checks_is_other_edge_unselected(p_incident_dominance_check_id) AND calc_incident_dominance_checks_is_other_edge_unique(p_incident_dominance_check_id) AND calc_incident_dominance_checks_is_dominated_by_second_cost(p_incident_dominance_check_id)))::boolean;
$$ LANGUAGE sql STABLE;

