-- Field: InstanceLowerBounds.CountOfLocalDegreeBounds
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_count_of_local_degree_bounds(p_instance_lower_bound_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM local_degree_bounds WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_lower_bounds WHERE instance_lower_bound_id = p_instance_lower_bound_id)))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_count_of_invalid_local_degree_bounds
-- Field: InstanceLowerBounds.CountOfInvalidLocalDegreeBounds
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_count_of_invalid_local_degree_bounds(p_instance_lower_bound_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM local_degree_bounds WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_lower_bounds WHERE instance_lower_bound_id = p_instance_lower_bound_id) AND calc_local_degree_bounds_is_two_cheapest_witness(local_degree_bound_id) = FALSE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_total_local_degree_bound_cost
-- Field: InstanceLowerBounds.TotalLocalDegreeBoundCost
-- Type: aggregation | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_total_local_degree_bound_cost(p_instance_lower_bound_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((SELECT COALESCE(SUM((calc_local_degree_bounds_local_bound_cost(local_degree_bound_id))::numeric), 0) FROM local_degree_bounds WHERE tsp_instance = (SELECT NULLIF(tsp_instance, '') FROM instance_lower_bounds WHERE instance_lower_bound_id = p_instance_lower_bound_id)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_lower_bound_cost
-- Field: InstanceLowerBounds.LowerBoundCost
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_lower_bound_cost(p_instance_lower_bound_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_instance_lower_bounds_base_lower_bound_cost(p_instance_lower_bound_id)) AS v) __safe_numeric), 0) + COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT supplemental_bound_adjustment FROM instance_lower_bounds WHERE instance_lower_bound_id = p_instance_lower_bound_id)) AS v) __safe_numeric), 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_is_certified
-- Field: InstanceLowerBounds.IsCertified
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_is_certified(p_instance_lower_bound_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_instance_lower_bounds_count_of_local_degree_bounds(p_instance_lower_bound_id) = calc_instance_lower_bounds_required_stop_count(p_instance_lower_bound_id) AND (calc_instance_lower_bounds_count_of_invalid_local_degree_bounds(p_instance_lower_bound_id))::NUMERIC = 0 AND calc_instance_lower_bounds_is_supplemental_bound_certified(p_instance_lower_bound_id)));
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_base_lower_bound_cost
-- Field: InstanceLowerBounds.BaseLowerBoundCost
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_base_lower_bound_cost(p_instance_lower_bound_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT (calc_instance_lower_bounds_total_local_degree_bound_cost(p_instance_lower_bound_id)) AS v) __safe_numeric), 0) / NULLIF(COALESCE(2, 0), 0)))::numeric;
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_count_of_certified_supplemental_term
-- Field: InstanceLowerBounds.CountOfCertifiedSupplementalTerms
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_count_of_certified_supplemental_term(p_instance_lower_bound_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COUNT(*) FROM tsp_bound_terms WHERE bound_certificate = (SELECT NULLIF(instance_lower_bound_id, '') FROM instance_lower_bounds WHERE instance_lower_bound_id = p_instance_lower_bound_id) AND counts_toward_adjustment = TRUE AND is_certified = TRUE))::integer;
$$ LANGUAGE sql STABLE;

-- calc_instance_lower_bounds_is_supplemental_bound_certified
-- Field: InstanceLowerBounds.IsSupplementalBoundCertified
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_instance_lower_bounds_is_supplemental_bound_certified(p_instance_lower_bound_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_instance_lower_bounds_count_of_certified_supplemental_term(p_instance_lower_bound_id) = (SELECT required_supplemental_term_count FROM instance_lower_bounds WHERE instance_lower_bound_id = p_instance_lower_bound_id))::boolean;
$$ LANGUAGE sql STABLE;

