RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(tsp_bound_term_id, '') FROM tsp_bound_terms WHERE tsp_bound_term_id = p_tsp_bound_term_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_tsp_bound_terms_term_value
-- Field: TSPBoundTerms.TermValue
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_tsp_bound_terms_term_value(p_tsp_bound_term_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT quantity FROM tsp_bound_terms WHERE tsp_bound_term_id = p_tsp_bound_term_id)) AS v) __safe_numeric), 0) * COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT unit_weight FROM tsp_bound_terms WHERE tsp_bound_term_id = p_tsp_bound_term_id)) AS v) __safe_numeric), 0) * COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT sign FROM tsp_bound_terms WHERE tsp_bound_term_id = p_tsp_bound_term_id)) AS v) __safe_numeric), 0))) AS v) __safe_numeric), 0)))::numeric;
$$ LANGUAGE sql STABLE;

