RETURNS BOOLEAN AS $$
  SELECT ((((SELECT degree_violation_count FROM tsp_derived_edge_sets WHERE tsp_derived_edge_set_id = p_tsp_derived_edge_set_id))::NUMERIC = 0 AND ((SELECT connected_component_count FROM tsp_derived_edge_sets WHERE tsp_derived_edge_set_id = p_tsp_derived_edge_set_id))::NUMERIC = 1 AND ((SELECT proper_subtour_count FROM tsp_derived_edge_sets WHERE tsp_derived_edge_set_id = p_tsp_derived_edge_set_id))::NUMERIC = 0));
$$ LANGUAGE sql STABLE;

-- calc_tsp_defect_profiles_name
-- Field: TSPDefectProfiles.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_tsp_defect_profiles_name(p_tsp_defect_profile_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(tsp_defect_profile_id, '') FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_tsp_defect_profiles_incidence_defect
-- Field: TSPDefectProfiles.IncidenceDefect
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_tsp_defect_profiles_incidence_defect(p_tsp_defect_profile_id TEXT)
RETURNS INTEGER AS $$
  SELECT (ABS((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT required_incidence FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0) - COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT observed_incidence FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0))))::integer;
$$ LANGUAGE sql STABLE;

-- calc_tsp_defect_profiles_connectivity_defect
-- Field: TSPDefectProfiles.ConnectivityDefect
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_tsp_defect_profiles_connectivity_defect(p_tsp_defect_profile_id TEXT)
RETURNS INTEGER AS $$
  SELECT (GREATEST((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT component_count FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0) - COALESCE(1, 0)), 0))::integer;
$$ LANGUAGE sql STABLE;

-- calc_tsp_defect_profiles_boundary_defect
-- Field: TSPDefectProfiles.BoundaryDefect
-- Type: calculated | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_tsp_defect_profiles_boundary_defect(p_tsp_defect_profile_id TEXT)
RETURNS INTEGER AS $$
  SELECT (GREATEST((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT required_boundary_crossings FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0) - COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT observed_boundary_crossings FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0)), 0))::integer;
$$ LANGUAGE sql STABLE;

-- calc_tsp_defect_profiles_cost_gap
-- Field: TSPDefectProfiles.CostGap
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_tsp_defect_profiles_cost_gap(p_tsp_defect_profile_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN (COALESCE((SELECT lower_bound_witnessed FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id), FALSE) AND COALESCE((SELECT upper_bound_witnessed FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id), FALSE)) THEN ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT upper_bound_cost FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0) - COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT lower_bound_cost FROM tsp_defect_profiles WHERE tsp_defect_profile_id = p_tsp_defect_profile_id)) AS v) __safe_numeric), 0)))::text ELSE (0)::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_tsp_defect_profiles_defect_vector
-- Field: TSPDefectProfiles.DefectVector
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_tsp_defect_profiles_defect_vector(p_tsp_defect_profile_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT(calc_tsp_defect_profiles_incidence_defect(p_tsp_defect_profile_id), '|', calc_tsp_defect_profiles_connectivity_defect(p_tsp_defect_profile_id), '|', calc_tsp_defect_profiles_boundary_defect(p_tsp_defect_profile_id), '|', calc_tsp_defect_profiles_cost_gap(p_tsp_defect_profile_id)))::text;
$$ LANGUAGE sql STABLE;

