-- calc_tsp_connected_degree_two_certificates_is_passing
-- Field: TSPConnectedDegreeTwoCertificates.IsPassing
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_connected_degree_two_certificates_is_passing(p_tsp_connected_degree_two_certificate_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT edge_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id) = (SELECT required_stop_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id) AND ((SELECT degree_violation_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id))::NUMERIC = 0 AND ((SELECT component_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id))::NUMERIC = 1 AND ((SELECT proper_subtour_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id))::NUMERIC = 0 AND (SELECT spanning_tree_edge_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id) = (COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT required_stop_count FROM tsp_connected_degree_two_certificates WHERE tsp_connected_degree_two_certificate_id = p_tsp_connected_degree_two_certificate_id)) AS v) __safe_numeric), 0) - COALESCE(1, 0))));
$$ LANGUAGE sql STABLE;

