-- calc_tsp_route_reconstructions_is_passing
-- Field: TSPRouteReconstructions.IsPassing
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_route_reconstructions_is_passing(p_tsp_route_reconstruction_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT reconstructed_stop_count FROM tsp_route_reconstructions WHERE tsp_route_reconstruction_id = p_tsp_route_reconstruction_id) = (SELECT required_stop_count FROM tsp_route_reconstructions WHERE tsp_route_reconstruction_id = p_tsp_route_reconstruction_id) AND (SELECT reconstructed_leg_count FROM tsp_route_reconstructions WHERE tsp_route_reconstruction_id = p_tsp_route_reconstruction_id) = (SELECT required_stop_count FROM tsp_route_reconstructions WHERE tsp_route_reconstruction_id = p_tsp_route_reconstruction_id) AND NOT (COALESCE((SELECT candidate_used_as_antecedent FROM tsp_route_reconstructions WHERE tsp_route_reconstruction_id = p_tsp_route_reconstruction_id), FALSE)) AND (SELECT NULLIF(status, '') FROM tsp_route_reconstructions WHERE tsp_route_reconstruction_id = p_tsp_route_reconstruction_id) = 'RECONSTRUCTED'))::boolean;
$$ LANGUAGE sql STABLE;

