$$ LANGUAGE sql STABLE;

-- calc_tsp_witness_normal_forms_semantic_key
-- Field: TSPWitnessNormalForms.SemanticKey
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_tsp_witness_normal_forms_semantic_key(p_tsp_witness_normal_form_id TEXT)
RETURNS TEXT AS $$
  SELECT (CONCAT((SELECT NULLIF(witness_shape, '') FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT NULLIF(tsp_instance, '') FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT covered_stop_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT required_stop_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT edge_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT total_cost FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT incidence_defect FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT connectivity_defect FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', (SELECT order_defect FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '|', COALESCE((SELECT NULLIF(boundary_signature, '') FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id), '')))::text;
$$ LANGUAGE sql STABLE;

-- calc_tsp_witness_normal_forms_is_valid
-- Field: TSPWitnessNormalForms.IsValid
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_witness_normal_forms_is_valid(p_tsp_witness_normal_form_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (((SELECT covered_stop_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id) = (SELECT required_stop_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id) AND ((SELECT incidence_defect FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id))::NUMERIC = 0 AND ((SELECT connectivity_defect FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id))::NUMERIC = 0 AND ((SELECT order_defect FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id))::NUMERIC = 0 AND (((SELECT NULLIF(witness_shape, '') FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id) = 'CYCLE' AND (SELECT edge_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id) = (SELECT required_stop_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id)) OR ((SELECT NULLIF(witness_shape, '') FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id) = 'PATH' AND (SELECT edge_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id) = (COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT required_stop_count FROM tsp_witness_normal_forms WHERE tsp_witness_normal_form_id = p_tsp_witness_normal_form_id)) AS v) __safe_numeric), 0) - COALESCE(1, 0))))));
$$ LANGUAGE sql STABLE;

-- calc_tsp_search_certificates_name
-- Field: TSPSearchCertificates.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_tsp_search_certificates_name(p_tsp_search_certificate_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(tsp_search_certificate_id, '') FROM tsp_search_certificates WHERE tsp_search_certificate_id = p_tsp_search_certificate_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_tsp_search_certificates_route_class_elimination_pct
-- Field: TSPSearchCertificates.RouteClassEliminationPct
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_tsp_search_certificates_route_class_elimination_pct(p_tsp_search_certificate_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN ((SELECT initial_route_class_count FROM tsp_search_certificates WHERE tsp_search_certificate_id = p_tsp_search_certificate_id))::NUMERIC = 0 THEN (0)::text ELSE (ROUND(((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT initial_route_class_count FROM tsp_search_certificates WHERE tsp_search_certificate_id = p_tsp_search_certificate_id)) AS v) __safe_numeric), 0) - COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT surviving_route_class_count FROM tsp_search_certificates WHERE tsp_search_certificate_id = p_tsp_search_certificate_id)) AS v) __safe_numeric), 0))) AS v) __safe_numeric), 0) / NULLIF(COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT initial_route_class_count FROM tsp_search_certificates WHERE tsp_search_certificate_id = p_tsp_search_certificate_id)) AS v) __safe_numeric), 0), 0))) AS v) __safe_numeric), 0) * COALESCE(100, 0)))::NUMERIC, (2)::INTEGER))::text END)::numeric;
$$ LANGUAGE sql STABLE;

