  SELECT ((SELECT NULLIF(obligation_kind, '') FROM tsp_frontier_obligations WHERE tsp_frontier_obligation_id = p_tsp_frontier_obligation_id) = 'IMPORTED_DEPENDENCY')::boolean;
$$ LANGUAGE sql STABLE;

