-- calc_tsp_convergence_measurements_semantic_compression_pct
-- Field: TSPConvergenceMeasurements.SemanticCompressionPct
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_tsp_convergence_measurements_semantic_compression_pct(p_tsp_convergence_measurement_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN ((SELECT surface_concept_count_before FROM tsp_convergence_measurements WHERE tsp_convergence_measurement_id = p_tsp_convergence_measurement_id))::NUMERIC = 0 THEN (0)::text ELSE (ROUND(((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT surface_concept_count_before FROM tsp_convergence_measurements WHERE tsp_convergence_measurement_id = p_tsp_convergence_measurement_id)) AS v) __safe_numeric), 0) - COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT primitive_count_after FROM tsp_convergence_measurements WHERE tsp_convergence_measurement_id = p_tsp_convergence_measurement_id)) AS v) __safe_numeric), 0))) AS v) __safe_numeric), 0) / NULLIF(COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT surface_concept_count_before FROM tsp_convergence_measurements WHERE tsp_convergence_measurement_id = p_tsp_convergence_measurement_id)) AS v) __safe_numeric), 0), 0))) AS v) __safe_numeric), 0) * COALESCE(100, 0)))::NUMERIC, (2)::INTEGER))::text END)::numeric;
$$ LANGUAGE sql STABLE;

