-- calc_search_metrics_search_elimination_pct
-- Field: SearchMetrics.SearchEliminationPct
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_search_metrics_search_elimination_pct(p_search_metric_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (CASE WHEN ((SELECT branch_count_before FROM search_metrics WHERE search_metric_id = p_search_metric_id))::NUMERIC = 0 THEN (0)::text ELSE (ROUND(((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT branch_count_before FROM search_metrics WHERE search_metric_id = p_search_metric_id)) AS v) __safe_numeric), 0) - COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT branch_count_after FROM search_metrics WHERE search_metric_id = p_search_metric_id)) AS v) __safe_numeric), 0))) AS v) __safe_numeric), 0) / NULLIF(COALESCE((SELECT CASE WHEN v::text ~ '^-?[0-9]*\.?[0-9]+$' THEN v::numeric ELSE NULL END FROM (SELECT ((SELECT branch_count_before FROM search_metrics WHERE search_metric_id = p_search_metric_id)) AS v) __safe_numeric), 0), 0))) AS v) __safe_numeric), 0) * COALESCE(100, 0)))::NUMERIC, (2)::INTEGER))::text END)::numeric;
$$ LANGUAGE sql STABLE;

-- calc_tsp_invariant_checks_actual_hamiltonian_cycle_witness
-- Field: TSPInvariantChecks.ActualHamiltonianCycleWitness
-- Type: lookup | DataType: boolean | Returns: BOOLEAN
