CREATE OR REPLACE FUNCTION calc_tsp_invariant_checks_actual_hamiltonian_cycle_witness(p_tsp_invariant_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT calc_candidate_tours_is_hamiltonian_cycle_witness((SELECT candidate_tour FROM tsp_invariant_checks WHERE tsp_invariant_check_id = p_tsp_invariant_check_id));
