-- calc_tsp_invariant_checks_is_hamiltonian_status_correct
-- Field: TSPInvariantChecks.IsHamiltonianStatusCorrect
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_invariant_checks_is_hamiltonian_status_correct(p_tsp_invariant_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT expected_hamiltonian_cycle_witness FROM tsp_invariant_checks WHERE tsp_invariant_check_id = p_tsp_invariant_check_id) = calc_tsp_invariant_checks_actual_hamiltonian_cycle_witness(p_tsp_invariant_check_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tsp_invariant_checks_is_optimality_status_correct
-- Field: TSPInvariantChecks.IsOptimalityStatusCorrect
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_invariant_checks_is_optimality_status_correct(p_tsp_invariant_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT expected_optimality_proved FROM tsp_invariant_checks WHERE tsp_invariant_check_id = p_tsp_invariant_check_id) = calc_tsp_invariant_checks_actual_optimality_proved(p_tsp_invariant_check_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tsp_invariant_checks_is_cost_correct
-- Field: TSPInvariantChecks.IsCostCorrect
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_invariant_checks_is_cost_correct(p_tsp_invariant_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((SELECT expected_total_travel_cost FROM tsp_invariant_checks WHERE tsp_invariant_check_id = p_tsp_invariant_check_id) = calc_tsp_invariant_checks_actual_total_travel_cost(p_tsp_invariant_check_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_tsp_invariant_checks_is_passing
-- Field: TSPInvariantChecks.IsPassing
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_tsp_invariant_checks_is_passing(p_tsp_invariant_check_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT ((calc_tsp_invariant_checks_is_hamiltonian_status_correct(p_tsp_invariant_check_id) AND calc_tsp_invariant_checks_is_optimality_status_correct(p_tsp_invariant_check_id) AND calc_tsp_invariant_checks_is_cost_correct(p_tsp_invariant_check_id)))::boolean;
$$ LANGUAGE sql STABLE;

